#include <bits/stdc++.h>
#define int long long
#define double long double
using namespace std;
const int MAXN = 105;
const int MAXM = 105;
int N, M;
int mp[MAXN];
int dp[MAXN][MAXM][MAXM];
int mask[MAXN], cnt;
bool chk (int x) {
	return !((x & (x << 1)) || (x & (x << 2)));
}
void solve() {
	for (int i = 0; i < ( 1 << M ); i++) {
		if (chk (i)) {
			mask[++cnt] = i;
		}
	}
	return;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> N >> M;
	for (int i = 1; i <= N; i++) {
		for (int j = 0; j < M; j++) {
			char k;
			cin >> k;
			if (k == 'H') {
				mp[i] |= (1 << j);
			}
		}
	}
	memset (dp, -1, sizeof (dp));
	solve ();
	for (int i = 1; i <= cnt; i++) {
		if (!(mask[i] & mp[1])) {
			dp[1][i][0] = __builtin_popcount (mask[i]);
		}
	}
	for (int h = 2; h <= N; h++ ) {
		for (int i = 1; i <= cnt; i++ ) {
			if (mask[i] & mp[h]) {
				continue;
			}
			for (int j = 1; j <= cnt; j++) {
				if ((mask[i] & mask[j]) || mask[j] & mp[h - 1])  {
					continue;
				}
				for (int k = 0; k <= cnt; k++) {
					if (k == 0 && h == 2 && dp[h - 1][j][0] != -1) {
						dp[h][i][j] = max (dp[h][i][j], dp[h - 1][j][0] + __builtin_popcount (mask[i]));
					}
					if (h >= 3 && !(mask[i] & mask[k]) && !( mp[h - 2] & mask[k] ) && dp[h - 1][j][k] != -1) {
						dp[h][i][j] = max (dp[h][i][j], dp[h - 1][j][k] + __builtin_popcount (mask[i]));
					}
				}
			}
		}
	}
	int ans = -0x3f3f3f3f;
	for (int i = 1; i <= cnt; i++ ) {
		for (int j = 0; j <= cnt; j++ ) {
			ans = max (ans, dp[N][i][j]);
		}
	}
	cout << ans;
	return 0;
}
